USE sales_db;

CREATE EXTERNAL TABLE sales_schema.sales
(
       [Outlet_Establishment_Year] VARCHAR(100)
,[Outlet_Location_Type] VARCHAR(100)
,[round(sum(Item_Outlet_Sales) AS total_sales, 2)] int
)
WITH (
    LOCATION    = 'github/data/',
    DATA_SOURCE = GoldLayer,
    FILE_FORMAT = DeltaFormat
);
